export const BUNDLE_PRICE = 249;
export const COURSE_PRICE = 99;

// Helper used in CourseView: pick correct lessons for active language
// Falls back to Swedish if translation missing
export function getLessons(course, lang) {
  if (lang === "en" && course.lessons_en) return course.lessons_en;
  if (lang === "es" && course.lessons_es) return course.lessons_es;
  return course.lessons;
}

